/**
 * MedX badge runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Status badges for order state, lot quality, and supplier tier labels.
 */
const BADGE_VARIANTS = Object.freeze({
  default: { bg: "bg-secondary", text: "text-secondary-foreground" },
  primary: { bg: "bg-primary", text: "text-primary-foreground" },
  success: { bg: "bg-emerald-500/15", text: "text-emerald-700" },
  warning: { bg: "bg-amber-500/15", text: "text-amber-700" },
  destructive: { bg: "bg-destructive/15", text: "text-destructive" },
  outline: { bg: "bg-transparent", text: "text-foreground", border: "border border-border" },
});

const STATUS_BADGE_MAP = Object.freeze({
  order: {
    draft: { label: "Draft", variant: "default" },
    pending: { label: "Pending", variant: "warning" },
    approved: { label: "Approved", variant: "primary" },
    shipped: { label: "Shipped", variant: "success" },
    delivered: { label: "Delivered", variant: "success" },
    cancelled: { label: "Cancelled", variant: "destructive" },
  },
  lot: {
    active: { label: "Active", variant: "success" },
    quarantine: { label: "Quarantine", variant: "warning" },
    expired: { label: "Expired", variant: "destructive" },
    recalled: { label: "Recalled", variant: "destructive" },
  },
  supplier: {
    A: { label: "Tier A", variant: "success" },
    B: { label: "Tier B", variant: "primary" },
    C: { label: "Tier C", variant: "warning" },
    suspended: { label: "Suspended", variant: "destructive" },
  },
});

const badgeCache = new Map();

function resolveBadge(domain, status) {
  const map = STATUS_BADGE_MAP[domain];
  if (!map) return null;
  const config = map[status];
  if (!config) return { label: status, variant: "default" };
  return {
    ...config,
    styles: BADGE_VARIANTS[config.variant] ?? BADGE_VARIANTS.default,
    domain,
    status,
  };
}

function createBadge(config) {
  const id = config.id ?? `medx-badge-${badgeCache.size + 1}`;
  const resolved = config.domain
    ? resolveBadge(config.domain, config.status)
  : {
      label: config.label ?? "Badge",
      variant: config.variant ?? "default",
      styles: BADGE_VARIANTS[config.variant ?? "default"],
    };

  const badge = {
    id,
    ...resolved,
    dot: Boolean(config.dot),
    removable: Boolean(config.removable),
    count: config.count ?? null,
  };
  badgeCache.set(id, badge);
  return badge;
}

function batchResolveBadges(items) {
  return items.map((item, index) =>
    createBadge({
      id: `batch-badge-${index}`,
      domain: item.domain,
      status: item.status,
      dot: item.dot,
    }),
  );
}

function formatBadgeDisplay(badge) {
  let text = badge.label;
  if (badge.count != null && badge.count > 0) {
    text = `${badge.label} (${badge.count > 99 ? "99+" : badge.count})`;
  }
  return { id: badge.id, text, variant: badge.variant, hasDot: badge.dot };
}

async function runMedxBadge() {
  console.log("[medx:ui:badge] runtime initialized");
  console.log(`[medx:ui:badge] variants=${Object.keys(BADGE_VARIANTS).length} domains=${Object.keys(STATUS_BADGE_MAP).length}`);

  const demoItems = [
    { domain: "order", status: "shipped" },
    { domain: "order", status: "pending" },
    { domain: "lot", status: "quarantine", dot: true },
    { domain: "lot", status: "expired" },
    { domain: "supplier", status: "A" },
    { domain: "supplier", status: "suspended" },
  ];

  const badges = batchResolveBadges(demoItems);
  createBadge({ label: "Notifications", variant: "destructive", count: 12 });

  const displays = Array.from(badgeCache.values()).map(formatBadgeDisplay);
  console.log(`[medx:ui:badge] cached=${badgeCache.size}`);
  console.log("[medx:ui:badge] displays", displays.map((d) => d.text).join(" | "));
  console.log("[medx:ui:badge] bootstrap complete");
}

module.exports = runMedxBadge;
